INSERT INTO `store_brand` VALUES (1,_binary 'Катран-Пневмо',_binary 'katran-pnevmo',_binary 'Акционерное общество «Катран-Пневмо» основано в 1990 году для оснащения судостроительной промышленности качественным ручным пневмоинструментом. 22 декабря 2014 года произошла реорганизация компании в форме ее преобразования в ООО «Катран-Пневмо».\r\n\r\nЗа более чем 20 лет работы нашими специалистами разработаны и запущены в производство более трех десятков единиц продукции: от пневматических станков для шлифовки клапанов арматуры трубопроводов и фаскоснимателей для труб диаметром 600-800 мм до пневмомашин для обработки гребных винтов и пресс-форм. Заказчиками разработок выступали атомные электростанции, предприятия судостроительной и автомобильной промышленности.',_binary 'uploads/brands/uploads/brands/katranpnevmo.jpg',_binary 'uploads/brands/uploads/brands/katranpnevmo_nXiP4LJ.jpg'),(2,_binary 'Daewoo',_binary 'daewoo','',_binary 'uploads/brands/daewoo.jpg',_binary 'uploads/brands/daewoo_aGA5cfH.jpg'),(3,_binary 'JSD Tools',_binary 'jsd-tools','',_binary 'uploads/brands/jsdtools.jpg',_binary 'uploads/brands/jsdtools_VEveMo6.jpg'),(4,_binary 'Китай',_binary 'kitaj','',_binary 'uploads/brands/china.jpg',_binary 'uploads/brands/china_vXXwozf.jpg'),(5,_binary 'Nanfang',_binary 'nanfang','',_binary 'uploads/brands/static/images/blank_prodimg_zTZqezw.jpg',_binary 'uploads/brands/static/images/blank_prodimg_EaReKvx.jpg'),(6,_binary 'U-Tools',_binary 'u-tools','',_binary 'uploads/brands/utools.jpg',_binary 'uploads/brands/utools_JQSFbIh.jpg'),(7,_binary 'СудоРПМ',_binary 'sudorpm','',_binary 'uploads/brands/sudorpm.jpg',_binary 'uploads/brands/sudorpm_LPQEM2q.jpg'),(8,_binary 'Россия',_binary 'rossiya','',_binary 'uploads/brands/russia.jpg',_binary 'uploads/brands/russia_l0gThlX.jpg'),(9,_binary 'ТЭМЗ',_binary 'temz','',_binary 'uploads/brands/temz_OBNnfpe.jpg',_binary 'uploads/brands/temz_0bg2QXp.jpg'),(10,_binary 'ТЗК',_binary 'tzk',_binary 'ООО «Томский завод Кузнецова» (ТЗК) – лидер в России по изготовлению пневматического оборудования  и станков для строительных, горнодобывающих и производственных предприятий. ТЗК изготавливает полный комплекс инструментов. Это оборудование для обработки металлов, сварочных работ, литейного производства, кузнечно-прессовых и термических процессов, шлифовальные станки.\r\nКомпания также изготавливает пневматический и ударно-режущий инструмент для работы с горными породами, углем, глиной, льдом, металлами, асфальтом и бетонными конструкциями. Это отбойные молотки, бетоноломы, зубило и многое другое.\r\nКомпания ТЗК отличается лояльными ценами, высоким качеством, надежностью и долговечностью предлагаемого товара.',_binary 'uploads/brands/uploads/brands/tzk.jpg',_binary 'uploads/brands/uploads/brands/tzk_HhU8EzT.jpg'),(11,_binary 'МЗПИ',_binary 'mzpi','',_binary 'uploads/brands/uploads/brands/static/images/blank_prodimg_WXJXZcQ.jpg',_binary 'uploads/brands/uploads/brands/static/images/blank_prodimg_WXJXZcQ_6dstcFH.jpg'),(12,_binary 'Hymair',_binary 'hymair','',_binary 'uploads/brands/hymair.jpg',_binary 'uploads/brands/hymair_C0oFRXY.jpg'),(13,_binary 'КМЗ',_binary 'kmz','',_binary 'uploads/brands/uploads/brands/static/images/blank_prodimg_VhwMqQc.jpg',_binary 'uploads/brands/uploads/brands/static/images/blank_prodimg_VhwMqQc_7Mccy4x.jpg');
