INSERT INTO `store_product` VALUES (1,_binary 'Пневмошлифмашина МПС-2215М (Катран-Пневмо)',_binary 'pnevmoshlifmashina-mps-2215m-katran-pnevmo',_binary 'Торцевая пневматическая шлифовальная машина МПС-2215М производства ООО \"Катран-Пневмо\" мощностью 2,0 кВт позволяет максимально быстро выполнить любые работы по металу. Патент № 19873.',29400,14,'2025-04-15 08:45:09.262012',1,1,_binary 'uploads/products/mps6500_2zwqu06.jpg',_binary 'uploads/products/thumb/uploads/products/mps6500_2zwqu06_IJoekF8.jpg',1,NULL,1,0,1,NULL),(4,_binary 'Пневмошлифмашина МП-006 (Катран-Пневмо)',_binary 'pnevmoshlifmashina-mp-006-katran-pnevmo',_binary 'Пневматическая шлифовальная машина МП-006 производства ООО \"Катран-Пневмо\" предназначена для обработки штампов и пресс-форм, шлифования и зачистки поверхностей и других аналогичных работ. Гарантийное и сервисное обслуживание, запчасти. Патент № 19875.',18000,16,'2025-04-15 08:45:29.989939',1,4,_binary 'uploads/products/mp006_kdYXxsd.jpg',_binary 'uploads/products/thumb/uploads/products/mp006_kdYXxsd_eIRlLxe.jpg',1,NULL,1,0,1,NULL),(15,_binary 'Пневмопривод ППФ-420',_binary 'pnevmoprivod-ppf-420',_binary 'Машина предназначена для использования в качестве привода механизмов различного специального производственно-технического назначения. Высокая надежность, гарантия. Шпиндель - внутренний конус Морзе 2.',0,18,'2025-04-15 08:45:10.473809',0,15,_binary 'uploads/products/ppf420_u9VAJlI.jpg',_binary 'uploads/products/thumb/uploads/products/ppf420_u9VAJlI.jpg',1,NULL,0,0,1,NULL),(17,_binary 'Пневмомолоток рубильный РМ-8А (Катран-Пневмо)',_binary 'pnevmomolotok-rubilnyi-rm-8a-katran-pnevmo',_binary 'Молоток рубильный пневматический РМ8А предназначен для обрубки на отливках остатков прибылей и заливов, удаления пригара и стержней, вырубки дефектов, подготовки отливок под заварку и других аналогичных работ. Гарантийное и сервисное обслуживание.\r\nПатент №122602.',36000,6,'2025-04-15 08:45:11.088744',0,17,_binary 'uploads/products/rm8_CIqve9k.jpg',_binary 'uploads/products/thumb/uploads/products/rm8_CIqve9k_5apYAj6.jpg',1,NULL,1,0,1,NULL),(18,_binary 'Пневмомолоток рубильный РМ-12А (Катран-Пневмо)',_binary 'pnevmomolotok-rubilnyi-rm-12a-katran-pnevmo',_binary 'Молоток рубильный пневматический РМ-12А предназначен для обрубки на отливках остатков прибылей и заливов, удаления пригара и стержней, вырубки дефектов, подготовки отливок под заварку и других аналогичных работ. Гарантийное и сервисное обслуживание.\r\nПатент № 122602.',36000,6,'2025-04-15 08:45:11.732393',0,18,_binary 'uploads/products/rm12_kmwxcgd.jpg',_binary 'uploads/products/thumb/uploads/products/rm12_kmwxcgd_xmoBq7j.jpg',1,NULL,1,0,1,NULL),(19,_binary 'Пневмомолоток рубильный РМ-16А (Катран-Пневмо)',_binary 'pnevmomolotok-rubilnyi-rm-16a-katran-pnevmo',_binary 'Молоток рубильный пневматический РМ-16А предназначен для обрубки на отливках остатков прибылей и заливов, удаления пригара и стержней, вырубки дефектов, подготовки отливок под заварку и других аналогичных работ. Гарантийное и сервисное обслуживание.\r\nПатент №122602.',36000,6,'2025-04-15 08:45:12.128231',0,19,_binary 'uploads/products/rm16_wJgpxkG.jpg',_binary 'uploads/products/thumb/uploads/products/rm16_wJgpxkG_SugYtJX.jpg',1,NULL,1,0,1,NULL),(31,_binary 'Пневмотрамбовка ТП-28А (Катран-Пневмо)',_binary 'pnevmotrambovka-tp-28a-katran-pnevmo',_binary 'Трамбовка пневматическая (пневмотрамбовка) виброзащищенная ТП-28А предназначена для работ по послойному уплотнению формовочной смеси в литейном производстве с толщиной единичного слоя до 300 мм, для уплотнения грунта в строительстве, дорожном строительстве, где невозможно применение громоздких трамбующих и укатывающих машин. Трамбовка ТП-28А является более надежным аналогом трамбовок ИП-4503 и ТПВ-8Б. Снабжена виброзащитой. Гарантийный и текущий ремонт. Поставка запчастей. Патент № 123354.',45000,11,'2025-04-15 08:45:16.871009',1,31,_binary 'uploads/products/tp28a_ie0gwUW.jpg',_binary 'uploads/products/thumb/uploads/products/tp28a_ie0gwUW_s3diL5q.jpg',1,NULL,0,0,1,NULL),(53,_binary 'Пневмосверлильная машина ИП-1026',_binary 'pnevmosverlilnaia-mashina-ip-1026',_binary 'ИП1026',0,10,'2025-04-15 08:32:21.707738',0,53,_binary 'uploads/products/ip1026_ihbhry7.jpg',_binary 'uploads/products/thumb/uploads/products/ip1026_ihbhry7.jpg',NULL,NULL,0,0,1,NULL),(54,_binary 'Пневмосверлильная машина ИП-1027',_binary 'pnevmosverlilnaia-mashina-ip-1027',_binary 'ИП1027',0,10,'2025-04-15 08:32:22.415570',0,54,_binary 'uploads/products/ip1027_oR8oWFn.jpg',_binary 'uploads/products/thumb/uploads/products/ip1027_oR8oWFn_TlWYe9b.jpg',3,NULL,0,0,1,NULL),(56,_binary 'Пневмоперфоратор ПП-63В2',_binary 'pnevmoperforator-pp-63v2',_binary 'Перфоратор ПП63 предназначен для бурения шпуров в бетоне, граните, горных породах. Различают седующие модификации:\nВ - пылеподавление водой\nБ - боковая промывка\nС - продувка',58200,7,'2025-04-15 09:00:33.357291',0,56,_binary 'uploads/products/pp36_gM1m5Uk.jpg',_binary 'uploads/products/thumb/uploads/products/pp36_gM1m5Uk.jpg',8,NULL,0,0,1,NULL),(58,_binary 'Пневмоперфоратор ПП-36В2',_binary 'pnevmoperforator-pp-36v2',_binary 'Перфоратор ПП36 предназначен для бурения шпуров в бетоне, граните, горных породах. Различают седующие модификации:\nВ - пылеподавление водой\nБ - боковая промывка\nС - продувка',58200,7,'2025-04-15 09:00:36.326763',0,58,_binary 'uploads/products/pp36_HaPJzk2.jpg',_binary 'uploads/products/thumb/uploads/products/pp36_HaPJzk2.jpg',8,NULL,0,0,1,NULL),(154,_binary 'Пика П-11 (ТЗК)',_binary 'pika-p-11-tzk',_binary 'Форма инструмента - пика.',318,22,'2025-04-15 08:59:50.451819',0,154,_binary 'uploads/products/p11tzk_gC4PmPW.jpg',_binary 'uploads/products/thumb/uploads/products/p11tzk_gC4PmPW.jpg',10,NULL,0,0,1,NULL),(237,_binary 'Пневмотрамбовка ТПВ-3А (Катран-Пневмо)',_binary 'pnevmotrambovka-tpv-3a-katran-pnevmo',_binary 'Трамбовка пневматическая (пневмотрамбовка) виброзащищенная ТПВ-3А предназначена для работ по послойному уплотнению формовочной смеси в литейном производстве. Верстачная пневмотрамбовка ТПВ-3А имеет компактные размеры и небольшой вес для удобства работы в ограниченных пространствах. Прочная конструкция корпуса и металлический башмак значительно продлевает срок эксплуатации. Инструмент не нагревается при работе. Оснащена повышенной виброзащитой. Гарантийный и текущий ремонт. Поставка запчастей.',36000,11,'2025-04-15 08:45:12.802468',1,237,_binary 'uploads/products/tpv3a_ZqMDzfV.jpg',_binary 'uploads/products/thumb/uploads/products/tpv3a_ZqMDzfV_itlsblJ.jpg',1,NULL,0,0,1,NULL),(279,_binary 'Блок подготовки воздуха БПВ-3.0',_binary 'blok-podgotovki-vozdukha-bpv-3-0',_binary 'Блок подготовки воздуха, включающий в себя влагоотделитель, масленку, регулятор давления, манометр.',10800,23,'2025-04-15 08:32:02.372403',0,279,_binary 'uploads/products/bpv3_Ay3h07b.jpg',_binary 'uploads/products/thumb/uploads/products/bpv3_Ay3h07b.jpg',NULL,NULL,0,0,1,NULL),(474,_binary 'Лопатка для ПШМ МПС-2215М',_binary 'lopatka-dlia-pshm-mps-2215m',_binary 'Лопатка текстолитовая для торцевой шлифовальной машины МПС-2215М (Катран-Пневмо)',300,32,'2025-04-15 08:32:18.681318',0,474,_binary 'uploads/products/lopatka-dlya-pshm-mps-2215m_X1wVU7r.jpg',_binary 'uploads/products/thumb/uploads/products/lopatka-dlya-pshm-mps-2215m_X1wVU7r.jpg',NULL,NULL,0,0,1,NULL),(505,_binary 'Пневмомолоток клепальный ИП-4009М (ТЭМЗ)',_binary 'pnevmomolotok-klepalnyi-ip-4009m-temz',_binary 'Молоток ИП4009 предназначен для расклепки заклепок в горячем состоянии при монтажно-сборочных работах в различных областях.',0,4,'2025-04-15 08:32:20.588754',0,505,_binary 'uploads/products/ip4009m_Yjnh5Yg.jpg',_binary 'uploads/products/thumb/uploads/products/ip4009m_Yjnh5Yg.jpg',NULL,NULL,0,0,1,NULL),(651,_binary 'Цанга 6 мм для МП-011 МП-006',_binary 'tsanga-6-mm-dlia-mp-011-mp-006',_binary 'Цанга 6 мм для пневматических шлифовальных машин МП-011 МП-006 производства Катран-Пневмо',1980,31,'2025-04-15 09:00:49.628004',0,651,_binary 'uploads/products/canga-6-mm-dlya-mp-011-mp-006.jp